// WF15 — Calculate aging for all open AR records
const records = $input.all();
const today = new Date();
today.setHours(0, 0, 0, 0);

const needs30 = [];
const needs60 = [];
const needs90 = [];
const statusUpdates = [];
const recordMap = {}; // ar_id → airtable record id

const summary = {
  current: { count: 0, total: 0 },
  days30: { count: 0, total: 0 },
  days60: { count: 0, total: 0 },
  days90plus: { count: 0, total: 0 },
  totalOutstanding: 0
};

for (const record of records) {
  const f = record.json.fields || record.json;
  const recId = record.json.id || f.id;
  const arId = f.ar_id;
  const dueDate = new Date(f.due_date);
  dueDate.setHours(0, 0, 0, 0);
  const balance = parseFloat(f.balance) || (parseFloat(f.amount) - parseFloat(f.amount_paid || 0));

  if (balance <= 0) continue;

  recordMap[arId] = recId;
  const daysOverdue = Math.floor((today - dueDate) / 86400000);
  let newStatus;

  if (daysOverdue <= 0) {
    newStatus = 'Current';
    summary.current.count++;
    summary.current.total += balance;
  } else if (daysOverdue <= 30) {
    newStatus = '30 Days';
    summary.days30.count++;
    summary.days30.total += balance;
    if (!f.alert_30_sent) {
      needs30.push({
        ar_id: arId, client_name: f.client_name, client_email: f.client_email,
        client_type: f.client_type?.name || f.client_type || '',
        invoice_number: f.invoice_number, invoice_date: f.invoice_date,
        due_date: f.due_date, amount: parseFloat(f.amount) || 0,
        balance, days_overdue: daysOverdue,
        payment_terms: f.payment_terms || 'Net 30',
        department: f.department || '', airtable_id: recId
      });
    }
  } else if (daysOverdue <= 60) {
    newStatus = '60 Days';
    summary.days60.count++;
    summary.days60.total += balance;
    if (!f.alert_60_sent) {
      needs60.push({
        ar_id: arId, client_name: f.client_name, client_email: f.client_email,
        client_type: f.client_type?.name || f.client_type || '',
        invoice_number: f.invoice_number, invoice_date: f.invoice_date,
        due_date: f.due_date, amount: parseFloat(f.amount) || 0,
        balance, days_overdue: daysOverdue,
        payment_terms: f.payment_terms || 'Net 30',
        department: f.department || '', airtable_id: recId
      });
    }
  } else {
    newStatus = '90+ Days';
    summary.days90plus.count++;
    summary.days90plus.total += balance;
    if (!f.alert_90_sent) {
      needs90.push({
        ar_id: arId, client_name: f.client_name, client_email: f.client_email,
        client_type: f.client_type?.name || f.client_type || '',
        invoice_number: f.invoice_number, invoice_date: f.invoice_date,
        due_date: f.due_date, amount: parseFloat(f.amount) || 0,
        balance, days_overdue: daysOverdue,
        payment_terms: f.payment_terms || 'Net 30',
        department: f.department || '', airtable_id: recId
      });
    }
  }

  summary.totalOutstanding += balance;

  // Track status changes
  const currentStatus = f.status?.name || f.status || '';
  if (currentStatus !== newStatus) {
    statusUpdates.push({ airtable_id: recId, newStatus });
  }
}

// Format EUR
const fmtEur = (n) => `€${n.toLocaleString('de-DE', {minimumFractionDigits: 2, maximumFractionDigits: 2})}`;

// Build Slack summary
let slackMsg = `📊 *DNEVNI PREGLED POTRAŽIVANJA — ${today.toLocaleDateString('de-DE')}*\n\n`;
slackMsg += `💰 Ukupna potraživanja: *${fmtEur(summary.totalOutstanding)}*\n\n`;
slackMsg += `   Tekuća (bez kašnjenja): ${summary.current.count} klijenata — ${fmtEur(summary.current.total)}\n`;
slackMsg += `   🟡 30 dana kašnjenja: ${summary.days30.count} klijenata — ${fmtEur(summary.days30.total)}\n`;
slackMsg += `   🟠 60 dana kašnjenja: ${summary.days60.count} klijenata — ${fmtEur(summary.days60.total)}\n`;
slackMsg += `   🔴 90+ dana kašnjenja: ${summary.days90plus.count} klijenata — ${fmtEur(summary.days90plus.total)}\n`;
slackMsg += `\n📧 Danas šaljemo:\n`;
slackMsg += `   • ${needs30.length} podsjetnika (30 dana)\n`;
slackMsg += `   • ${needs60.length} opomena (60 dana)\n`;
slackMsg += `   • ${needs90.length} zadnjih opomena (90+ dana)\n`;

if (summary.days90plus.count > 0) {
  slackMsg += `\n⚠️ *KRITIČNO — Klijenti sa 90+ dana kašnjenja:*\n`;
  for (const acc of needs90) {
    slackMsg += `   • ${acc.client_name} — ${fmtEur(acc.balance)} (${acc.days_overdue} dana)\n`;
  }
  slackMsg += `   @zoran @martin`;
}

return [{
  json: {
    needs30, needs60, needs90, statusUpdates, summary, recordMap,
    has30: needs30.length > 0,
    has60: needs60.length > 0,
    has90: needs90.length > 0,
    hasOverdue: summary.days30.count + summary.days60.count + summary.days90plus.count > 0,
    slackMessage: slackMsg,
    todayStr: today.toISOString().split('T')[0]
  }
}];

// Output one item per AR record needing a status update
const data = $('Code - Calculate Aging').first().json;
return data.statusUpdates.map(u => ({
  json: { recordId: u.airtable_id, newStatus: u.newStatus }
}));

