// Parse Kimi response and output one item per email
const response = $input.first().json;
const content = response.choices[0].message.content;
const parsed = JSON.parse(content.replace(/```json|```/g, '').trim());
const agingData = $('Code - Calculate Aging').first().json;

return parsed.emails.map(email => ({
  json: {
    to: email.client_email,
    subject: email.subject,
    body: email.body,
    cc: '',
    ar_id: email.ar_id,
    client_name: email.client_name,
    airtable_record_id: agingData.recordMap[email.ar_id],
    tier: 30,
    flagField: 'alert_30_sent',
    eventType: 'AR_REMINDER_30_SENT'
